VALUES
  ('judicial-d35ec6db-moex-00267', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲登記為A屋所有人。關於甲如何行使A屋所有權，下列敘述，何者錯誤？', '["甲得將A屋所有權讓與他人", "甲得請求無權占有A屋之人返還A屋", "甲得使用收益A屋", "甲得於A屋上設定普通地上權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00268', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於不動產役權之敘述，何者錯誤？', '["不動產役權係以他人不動產供特定便宜之用為目的", "不動產役權係需役不動產之從權利", "不動產役權因時效而取得者，以繼續並表見者為限", "不動產役權不得就自己之不動產設定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00269', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲女未婚生下乙女，在乙5歲時，將乙出養於丙、丁夫妻，並與丙之母親戊共同生活。10年後， 某日丙、丁不幸遭遇空難，同時死亡。乙為賺取學費，欲在己經營之速食店打工，其僱傭契約應 經下列何者允許？', '["無庸得任何人之允許", "甲", "乙之生父", "戊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00270', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲已喪妻，有子女乙、丙二人。甲培養乙子赴美留學花費新臺幣（下同）500萬元。丙女結婚時， 甲花費500萬元購買小套房一間贈與丙。甲死亡時留有財產500萬元。甲之遺產分割時，乙可分 得多少遺產？', '["0元", "250萬元", "500萬元", "750萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00271', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲受監護宣告，法院選定其女乙為監護人。乙所為之下列行為，何者應經法院許可？', '["甲被診斷為末期病人，意識昏迷，乙同意不實施維生醫療", "甲罹患長期慢性病，需要醫護服務，乙代理甲與長期照顧機構訂立入住契約", "甲需要醫藥費，活期存款金額不足，乙代理甲將丙銀行之定存解約", "甲所有之A屋過度老舊，乙代理甲將A屋與其基地為對價，與建商丁訂立都更合建契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00272', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲立遺囑將百萬鑽戒遺贈媳婦乙。某日甲之友人丙因應酬需要，向甲商借該鑽戒佩戴。惟該鑽戒 不慎滅失，甲因此氣急攻心而死。甲所為遺贈之效力為何？', '["因遺囑無效，遺贈亦歸於無效", "遺贈視為撤回", "推定以甲對丙之損害賠償請求權為遺贈", "遺贈有效，乙僅得請求丙交付同等價值之鑽戒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00273', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者具有完全行為能力？', '["現年17歲之甲", "現年18歲之乙", "現年19歲已離婚之丙", "現年20歲受監護宣告之丁 20420 20520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00274', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '15歲之甲未經法定代理人允許，所為下列之法律行為，何者有效？', '["單獨行為", "處分不動產", "日常生活所必需之行為", "設定普通抵押權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00275', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於輔助宣告之敘述，何者錯誤？', '["受輔助宣告人並未喪失行為能力", "受輔助宣告人之財產，應由輔助人管理", "法院得依聲請，指定受輔助宣告人所為之法律行為金額在新臺幣50,000元以上者，須經輔助人 同意", "法院得依聲請，指定受輔助宣告人申辦手機門號及辦理信用卡之法律行為，經輔助人同意方為 有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00276', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者非屬不法侵害人格利益之情形？', '["新聞網站未加查證，於明知報導內容不實後，卻拒絕將該報導自系爭網站移除，繼續供他人任 意連結轉載", "於他人居住區域發出超越一般人社會生活所能容忍之噪音", "新聞媒體對於雙方均非公眾人物之私權爭端，揭載足資識別之個人資料", "利用購買人輕率無經驗而使其購買非必要之高價商品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
